VALUES
  ('cpa-moex-00711', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司董事長甲於民國106年1月4日賣出A公司股票5,000股，每股50元，1月25日賣 出8,000股，每股68元，2月21日賣出5,000股，每股45元，之後於同年4月11日買進3,000 股，每股48元，5月10日買進8,000股，每股57元，6月1日買進6,000股，每股65元。在甲 買賣期間，其交易之A公司股票未有分配股息情事。試問A公司對甲之買賣可否及行使多少金 額之歸入權？ 60,000 元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅 94,000 元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅 115,000元及計算差價利益之最後一筆交易日起至交付公司時的利息， 並得扣除支付證券商之手續費及證券交易稅', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00712', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何種證券市場操縱行為，學理上稱為沖洗買賣？ 報買賣而相對成交 連續以高價買入或以低價賣出 售，或購買有價證券時，使約定人同時為購買或出售之相對行為 達倒貨出脫目的', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00713', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '證券交易法對於公開說明書之規範，下列敘述，何者正確？ 發行人負連帶賠償責任 負賠償責任', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00714', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法對於公開發行公司財務報告之相關規範，下列何者正確？①公開發行公司須於每 會計年度終了後六個月內，公告並申報會計師查核簽證、董事會通過及監察人承認之年度財務報', '["公開發行公司須於每會計年度第一季、第二季及第三季終了後三十日內，公告並申報經會 計師核閱及提報董事會之財務報告", "上市公司依法須公告、申報之財務報告事項，尚須將抄本 送證券交易所", "公開發行公司在重整期間，仍須依法揭露財務報告", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00715', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法對於財務資訊不實之民事責任規範，下列何者正確？①資訊不實之民事責任主體', '["資訊不實之民事責任主體中，發行人之職員，曾在財務 報告上簽名或蓋章者，負推定過失責任", "資訊不實之民事責任主體中，辦理財務報告簽證之會 計師，負過失責任", "資訊不實之民事責任，其損害賠償請求權，自募集、發行或買賣之日起逾 二年間不行使而消滅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00716', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲得知A上櫃公司獲利極佳，故進而取得A上櫃公司9%的股份，甲聽說我國證券交易法有「大 量取得股權之申報」制度。下列敘述，何者錯誤？ 10%之股份 586號解釋，證券交易法第43條之1第1項的「共同取得」，應以意思聯 絡為必要', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00717', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司計劃於本年度召開的股東會中進行全部董監改選。該公司為強化董事專業能力，A公 司之董事長甲商請多位已經在同業其他公司擔任董事之知名人士同意出任 A 公司董事。為能排 除競業禁止的疑慮，A公司股東會開會通知的討論事項中，除「董監改選案」，亦列上「解除董 事競業禁止限制案」，該議案之內容為：「為公司利益，擬解除本公司全體董事競業禁止之限制。」 此一作法適法性，下列敘述，何者正確？ A公司為求慎重，在股東會召集事由中加以列舉，當屬適法 A公司之作法已符合法律要求，當屬適法 體董事概括進行', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00718', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公開發行公司（下稱 A 公司），設有董事 9 席，公司為精簡人事，並達到議事效率之目的， 變更章程將公司董事席次減為3席。同時，A公司的大股東B股份有限公司於董事選舉議案中， 推派其代表人甲當選為董事；又於監察人之選舉議案中，推派其代表人乙當選為監察人。則 A 公司變更章程是否有效？又甲、乙分別當選為董事與監察人是否合法？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00719', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 公司主要業務係為上市公司代銷其發行之有價證券，由此可推知 A 公司屬於下列何者證券商 類型？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00720', 'cpa', 'cpa-moex-108-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A 上市公司依董事會之決議，因維護信用及股東權益之必要將於集中交易市場買回 A 公司股份 50萬股，並辦理銷除股份。下列敘述，何者正確？ A公司買回股份，應於買回之日起一年內辦理變更登記 A公司董事會之決議及執行情形，除非有因故未買回股份之情形外，否則應於A公司最近一次 之股東會報告 A公司買回股份，須經董事會三分之二以上董事之出席及出席董事超過二分之一同意，方為適法 A公司買回的股份之數量比例，不得超過A公司已發行股份總數3%', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "899745575a22", "answer_pdf_sha1": "afac5c7d1a19", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
